// ═══════════════════════════════════════
// PAINEL CENTRAL — Resumo do Data Core
// ═══════════════════════════════════════

const memorias = $('📋 Todas as Memórias').all();
const imagens = $('🖼️ Listar Imagens').all().filter(i => i.json.name && !i.json.name.endsWith('/'));
const docs = $('📄 Listar Documentos').all().filter(i => i.json.name && !i.json.name.endsWith('/'));

// Contagem por categoria
const categorias = {};
morias.forEach(m => {
  const cat = m.json.category || 'sem_categoria';
  categorias[cat] = (categorias[cat] || 0) + 1;
});

// Contagem por skill
const skills = {};
memorias.forEach(m => {
  const sk = m.json.origin_skill || 'desconhecido';
  skills[sk] = (skills[sk] || 0) + 1;
});

// Memórias recentes (últimas 5)
const recentes = memorias.slice(0, 5).map(m => {
  const d = new Date(m.json.created_at);
  return `${d.toLocaleDateString('pt-PT')} — ${m.json.title}`;
});

// Tamanho total de media
const totalSizeImages = imagens.reduce((acc, i) => acc + (i.json.metadata?.size || 0), 0);
const totalSizeDocs = docs.reduce((acc, i) => acc + (i.json.metadata?.size || 0), 0);
const totalSizeMB = ((totalSizeImages + totalSizeDocs) / (1024 * 1024)).toFixed(2);

return [{
  json: {
    '🧠 DASHBOARD DATA CORE': '════════════════════════════════',
    '': '',
    '📋 MEMÓRIAS': `${memorias.length} registos`,
    '📂 Por Categoria': Object.entries(categorias).map(([k,v]) => `${k} (${v})`).join(' · '),
    '🔧 Por Skill': Object.entries(skills).map(([k,v]) => `${k} (${v})`).join(' · '),
    ' ': '',
    '🖼️ MEDIA': `${imagens.length} imagens · ${docs.length} documentos`,
    '💾 Espaço Usado': `${totalSizeMB} MB`,
    '  ': '',
    '📝 ÚLTIMAS MEMÓRIAS': '',
    ...Object.fromEntries(recentes.map((r, i) => [`  ${i+1}.`, r])),
    '   ': '',
    '⏰ Atualizado': new Date().toLocaleString('pt-PT'),
  }
}];

// Tabela detalhada de memórias
const memorias = $('📋 Todas as Memórias').all();

return memorias.map(m => {
  const d = m.json;
  const data = new Date(d.created_at);
  return {
    json: {
      'Título': d.title || 'Sem título',
      'Categoria': d.category || '-',
      'Descrição': (d.description || '').substring(0, 80),
      'Skill': d.origin_skill || '-',
      'Data': data.toLocaleDateString('pt-PT'),
      'Hora': data.toLocaleTimeString('pt-PT', {hour:'2-digit', minute:'2-digit'}),
    }
  };
});

// Tabela de ficheiros (imagens + docs)
const imagens = $('🖼️ Listar Imagens').all().filter(i => i.json.name && !i.json.name.endsWith('/'));
const docs = $('📄 Listar Documentos').all().filter(i => i.json.name && !i.json.name.endsWith('/'));

const baseImgUrl = 'https://wbmujojscykyngkmzner.supabase.co/storage/v1/object/public/images/';
const baseDocUrl = 'https://wbmujojscykyngkmzner.supabase.co/storage/v1/object/public/documents/';

const allFiles = [
  ...imagens.map(i => ({
    json: {
      'Nome': i.json.name,
      'Tipo': '🖼️ Imagem',
      'Tamanho': i.json.metadata?.size ? (i.json.metadata.size / 1024).toFixed(1) + ' KB' : 'N/A',
      'URL': baseImgUrl + i.json.name,
    }
  })),
  ...docs.map(d => ({
    json: {
      'Nome': d.json.name,
      'Tipo': '📄 Documento',
      'Tamanho': d.json.metadata?.size ? (d.json.metadata.size / 1024).toFixed(1) + ' KB' : 'N/A',
      'URL': baseDocUrl + d.json.name,
    }
  }))
];

if (allFiles.length === 0) {
  return [{ json: { 'Media': 'Nenhum ficheiro encontrado ainda. Use o Data Core para fazer upload!' } }];
}

return allFiles;
